// ── Set String Property ──

bool editor_setString(Registry& reg, u32 e, const std::string& comp, const std::string& field, const std::string& value) {
    auto entity = static_cast<Entity>(e);
    if (!reg.valid(entity)) return false;
    if (comp == "BitmapText") {
        if (!reg.has<esengine::ecs::BitmapText>(entity)) return false;
        auto& c = reg.get<esengine::ecs::BitmapText>(entity);
        if (field == "text") { c.text = value; }
        else { return false; }
        return true;
    } else if (comp == "SpineAnimation") {
        if (!reg.has<esengine::ecs::SpineAnimation>(entity)) return false;
        auto& c = reg.get<esengine::ecs::SpineAnimation>(entity);
        if (field == "skeletonPath") { c.skeletonPath = value; }
        else if (field == "atlasPath") { c.atlasPath = value; }
        else if (field == "skin") { c.skin = value; }
        else if (field == "animation") { c.animation = value; }
        else { return false; }
        c.needsReload = true;
        return true;
    } else if (comp == "StateMachine") {
        if (!reg.has<esengine::ecs::StateMachine>(entity)) return false;
        auto& c = reg.get<esengine::ecs::StateMachine>(entity);
        if (field == "current") { c.current = value; }
        else if (field == "previous") { c.previous = value; }
        else { return false; }
        return true;
    } else if (comp == "StateVisuals") {
        if (!reg.has<esengine::ecs::StateVisuals>(entity)) return false;
        auto& c = reg.get<esengine::ecs::StateVisuals>(entity);
        if (field == "slot0Name") { c.slot0Name = value; }
        else if (field == "slot1Name") { c.slot1Name = value; }
        else if (field == "slot2Name") { c.slot2Name = value; }
        else if (field == "slot3Name") { c.slot3Name = value; }
        else if (field == "slot4Name") { c.slot4Name = value; }
        else if (field == "slot5Name") { c.slot5Name = value; }
        else if (field == "slot6Name") { c.slot6Name = value; }
        else if (field == "slot7Name") { c.slot7Name = value; }
        else { return false; }
        return true;
    }
    return false;
}

// ── Get String Property ──

std::string editor_getString(Registry& reg, u32 e, const std::string& comp, const std::string& field) {
    auto entity = static_cast<Entity>(e);
    if (!reg.valid(entity)) return std::string{};
    if (comp == "BitmapText") {
        if (!reg.has<esengine::ecs::BitmapText>(entity)) return std::string{};
        const auto& c = reg.get<esengine::ecs::BitmapText>(entity);
        if (field == "text") { return c.text; }
    } else if (comp == "SpineAnimation") {
        if (!reg.has<esengine::ecs::SpineAnimation>(entity)) return std::string{};
        const auto& c = reg.get<esengine::ecs::SpineAnimation>(entity);
        if (field == "skeletonPath") { return c.skeletonPath; }
        else if (field == "atlasPath") { return c.atlasPath; }
        else if (field == "skin") { return c.skin; }
        else if (field == "animation") { return c.animation; }
    } else if (comp == "StateMachine") {
        if (!reg.has<esengine::ecs::StateMachine>(entity)) return std::string{};
        const auto& c = reg.get<esengine::ecs::StateMachine>(entity);
        if (field == "current") { return c.current; }
        else if (field == "previous") { return c.previous; }
    } else if (comp == "StateVisuals") {
        if (!reg.has<esengine::ecs::StateVisuals>(entity)) return std::string{};
        const auto& c = reg.get<esengine::ecs::StateVisuals>(entity);
        if (field == "slot0Name") { return c.slot0Name; }
        else if (field == "slot1Name") { return c.slot1Name; }
        else if (field == "slot2Name") { return c.slot2Name; }
        else if (field == "slot3Name") { return c.slot3Name; }
        else if (field == "slot4Name") { return c.slot4Name; }
        else if (field == "slot5Name") { return c.slot5Name; }
        else if (field == "slot6Name") { return c.slot6Name; }
        else if (field == "slot7Name") { return c.slot7Name; }
    }
    return std::string{};
}

